1	import { vi, describe, it, expect, beforeEach } from 'vitest';
2	import request from 'supertest';
3	import express, { type Request, type Response, type NextFunction } from 'express';
4	import cors from 'cors';
5	
6	// vi.hoisted ensures mocks are available inside the vi.mock factory (hoisted above imports)
7	const mockGet = vi.hoisted(() => vi.fn());
8	const mockPost = vi.hoisted(() => vi.fn());
9	
10	vi.mock('axios', () => ({
11	  default: {
12	    create: vi.fn(() => ({
13	      get: mockGet,
14	      post: mockPost,
15	    })),
16	  },
17	}));
18	
19	// Import after mocks are registered
20	import fibaroRouter from './fibaro.js';
21	import { invalidateCache } from '../integrations/fibaro/client.js';
22	import { createRequireAuth } from '../middleware/auth.js';
23	import rateLimit from 'express-rate-limit';
24	import helmet from 'helmet';
25	
26	const API_TOKEN = process.env.API_TOKEN!;
27	
28	const app = express();
29	app.use(helmet());
30	app.use(cors({ origin: ['http://localhost:5173'], methods: ['GET', 'POST'], allowedHeaders: ['Authorization', 'Content-Type'] }));
31	app.use(express.json());
32	app.use('/api/fibaro', createRequireAuth(API_TOKEN));
33	app.use('/api/fibaro', fibaroRouter);
34	app.use((err: { status?: number; type?: string }, _req: Request, res: Response, next: NextFunction) => {
35	  if (err.type === 'entity.parse.failed') {
36	    res.status(400).json({ error: 'Invalid JSON body' });
37	    return;
38	  }
39	  next(err);
40	});
41	
42	const AUTH = { Authorization: 'Bearer test-token' };
43	
44	describe('requireAuth middleware', () => {
45	  beforeEach(() => {
46	    mockGet.mockReset();
47	    invalidateCache('/api/devices');
48	  });
49	
50	  it('returns 401 when Authorization header is missing', async () => {
51	    const res = await request(app).get('/api/fibaro/devices');
52	    expect(res.status).toBe(401);
53	    expect(res.body).toEqual({ error: 'Unauthorized' });
54	  });
55	
56	  it('returns 401 when token is wrong', async () => {
57	    const res = await request(app)
58	      .get('/api/fibaro/devices')
59	      .set('Authorization', 'Bearer wrong-token');
60	    expect(res.status).toBe(401);
61	  });
62	
63	  it('returns 200 when token is correct', async () => {
64	    mockGet.mockResolvedValueOnce({ data: [] });
65	    const res = await request(app)
66	      .get('/api/fibaro/devices')
67	      .set(AUTH);
68	    expect(res.status).toBe(200);
69	  });
70	
71	  it('401 response includes CORS allow-origin header for cross-origin clients', async () => {
72	    const res = await request(app)
73	      .get('/api/fibaro/devices')
74	      .set('Origin', 'http://localhost:5173');
75	    // No Authorization header — must return 401
76	    expect(res.status).toBe(401);
77	    // CORS must be present so the browser can read the error body
78	    expect(res.headers['access-control-allow-origin']).toBe('http://localhost:5173');
79	  });
80	
81	  it('401 response with wrong token includes CORS allow-origin header', async () => {
82	    const res = await request(app)
83	      .get('/api/fibaro/devices')
84	      .set('Authorization', 'Bearer wrong-token')
85	      .set('Origin', 'http://localhost:5173');
86	    expect(res.status).toBe(401);
87	    expect(res.headers['access-control-allow-origin']).toBe('http://localhost:5173');
88	  });
89	});
90	
91	describe('rate limiter', () => {
92	  const limiterApp = express();
93	  limiterApp.use(express.json());
94	  limiterApp.use(cors({ origin: ['http://localhost:5173'], methods: ['GET', 'POST'], allowedHeaders: ['Authorization', 'Content-Type'] }));
95	  limiterApp.use('/api/fibaro', createRequireAuth(API_TOKEN));
96	  limiterApp.use('/api/fibaro', rateLimit({ max: 2, windowMs: 60000, standardHeaders: true, legacyHeaders: false, message: { error: 'Too many requests' } }));
97	  limiterApp.use('/api/fibaro', fibaroRouter);
98	
99	  beforeEach(() => {
100	    mockGet.mockReset();
101	    mockGet.mockResolvedValue({ data: [] });
102	    invalidateCache('/api/devices');
103	  });
104	
105	  it('returns 429 after exceeding the limit', async () => {
106	    await request(limiterApp).get('/api/fibaro/devices').set(AUTH);
107	    await request(limiterApp).get('/api/fibaro/devices').set(AUTH);
108	    const res = await request(limiterApp).get('/api/fibaro/devices').set(AUTH);
109	    expect(res.status).toBe(429);
110	    expect(res.body).toEqual({ error: 'Too many requests' });
111	  });
112	
113	  it('unauthenticated requests do not count against the rate limit budget', async () => {
114	    // Use a fresh app with its own rate limiter instance so prior tests don't affect the budget
115	    const freshApp = express();
116	    freshApp.use(express.json());
117	    freshApp.use('/api/fibaro', createRequireAuth(API_TOKEN));
118	    freshApp.use('/api/fibaro', rateLimit({ max: 2, windowMs: 60000, standardHeaders: true, legacyHeaders: false, message: { error: 'Too many requests' } }));
119	    freshApp.use('/api/fibaro', fibaroRouter);
120	
121	    // Send 2 unauthenticated requests (401, should not consume budget)
