14	function StatCard({ icon, label, value, sub, color = 'text-blue-400' }: StatCardProps) {
15	  return (
16	    <div className="bg-gray-800 rounded-xl p-5 border border-gray-700">
17	      <div className="flex items-center gap-3 mb-3">
18	        <div className={`${color}`}>{icon}</div>
19	        <span className="text-sm text-gray-400">{label}</span>
20	      </div>
21	      <p className="text-2xl font-bold text-white">{value}</p>
22	      {sub && <p className="text-xs text-gray-500 mt-1">{sub}</p>}
23	    </div>
24	  );
25	}
