27	export default function Dashboard() {
28	  const { data: devices = [], isLoading: loadingDevices, isError } = useDevices();
29	  const { data: rooms = [] } = useRooms();
30	  const { data: weather } = useWeather();
31	  const { data: scenes = [] } = useScenes();
32	
33	  const stats = useMemo(() => {
34	    const categories = devices.map(d => ({ device: d, cat: categorizeDevice(d.type) }));
35	    const lights = categories.filter(({ cat }) => cat === 'light' || cat === 'dimmer');
36	    const lightsOn = lights.filter(({ device: d }) => isDeviceOn(d)).length;
37	    const totalLights = lights.length;
38	    const safetyAlerts = categories.filter(({ cat, device: d }) =>
39	      cat === 'safety' && isDeviceOn(d)
40	    ).length;
41	    const offlineDevices = devices.filter(d => d.properties.dead).length;
42	    const totalPower = devices.filter(d => !d.properties.dead).reduce((sum, d) => sum + (d.properties.power ?? 0), 0);
43	    const thermostats = categories.filter(({ cat }) => cat === 'thermostat').map(({ device }) => device);
44	    const avgTemp = thermostats.length > 0
45	      ? (thermostats.reduce((s, d) => s + (typeof d.properties.value === 'number' ? d.properties.value : 0), 0) / thermostats.length).toFixed(1)
46	      : '--';
47	    return { lightsOn, totalLights, safetyAlerts, offlineDevices, totalPower, thermostats, avgTemp };
48	  }, [devices]);
49	
50	  const { lightsOn, totalLights, safetyAlerts, offlineDevices, totalPower, thermostats, avgTemp } = stats;
51	
52	  const roomStats = useMemo(() =>
53	    rooms.map(room => {
54	      const roomDevices = devices.filter(d => d.roomID === room.id);
