70	  }
71	
72	  if (isError) {
73	    return (
74	      <div role="alert" className="flex flex-col items-center justify-center h-64 gap-3">
75	        <AlertTriangle className="text-red-400" size={32} />
76	        <p className="text-red-400 font-medium">Failed to load devices</p>
77	        <p className="text-gray-500 text-sm">Check that Fibaro HC3 is reachable</p>
