80	  }
81	
82	  return (
83	    <div className="p-6">
84	      <div className="mb-6">
85	        <h2 className="text-2xl font-bold text-white">Dashboard</h2>
86	        <p className="text-gray-400 text-sm mt-1">{rooms.length} rooms · {devices.length} devices</p>
87	      </div>
88	
89	      {safetyAlerts > 0 && (
90	        <div role="alert" className="mb-6 bg-red-900/30 border border-red-500/50 rounded-xl p-4 flex items-center gap-3">
91	          <AlertTriangle className="text-red-400" size={20} />
92	          <div>
93	            <p className="text-red-300 font-medium">Safety Alert</p>
